import type { TZDate } from '@date-fns/tz';
import type { RequireAtLeastOne } from 'type-fest';
import type { CalendarType } from './types/calendarConfiguration.js';
import type { BehaviorTrackingProps } from '../../core/types/behavior-tracking-props.js';
import type { DataTestId } from '../../core/types/data-props.js';
import type { FormControlProps } from '../../core/types/form-control-props.js';
import type { MaskingProps } from '../../core/types/masking-props.js';
import type { StylingProps } from '../../core/types/styling-props.js';
import type { Timeframe } from '../../core/types/time.js';
/** @internal */
export type CalendarValueType<Type extends CalendarType> = Type extends 'range' ? RequireAtLeastOne<Timeframe> | RequireAtLeastOne<{
    from: string;
    to: string;
}> | null : string | null | Date;
/** @internal */
export type CalendarStrictValueType<Type extends CalendarType> = Type extends 'range' ? Timeframe | null : string | null;
/** @internal */
export type CalendarProps<Type extends CalendarType> = FormControlProps<CalendarValueType<Type>, (date: CalendarStrictValueType<Type>) => void> & StylingProps & MaskingProps & DataTestId & BehaviorTrackingProps & {
    /** The earliest selectable date. It will always consider the start of the day as time. */
    min?: string;
    /** The latest selectable date. It will always consider the end of the day as time. */
    max?: string;
    /** Determines the calendar type. Single allows the selection of one date and range allows a range selection with a from and to value.
     * @defaultValue 'single'
     */
    type?: Type;
    /**
     * The precision of the time shown in the display value.
     * @defaultValue 'minutes'
     */
    precision?: 'minutes' | 'seconds' | 'milliseconds';
};
/** @internal */
export interface SelectMonthViewItems {
    months: TZDate[];
}
